--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `shop_id` bigint(20) NOT NULL,
  `region` varchar(5) DEFAULT NULL,
  `order_sn` varchar(50) NOT NULL,
  `order_status` varchar(30) DEFAULT NULL,
  `is_final_status` tinyint(1) DEFAULT 0,
  `merchandise_subtotal` decimal(12,2) DEFAULT NULL,
  `total_amount` decimal(12,2) DEFAULT NULL,
  `currency` varchar(10) DEFAULT NULL,
  `original_price` decimal(12,2) DEFAULT NULL,
  `seller_discount` decimal(12,2) DEFAULT NULL,
  `voucher_from_seller` decimal(12,2) DEFAULT NULL,
  `voucher_from_shopee` decimal(12,2) DEFAULT NULL,
  `coins_offset` decimal(12,2) DEFAULT NULL,
  `buyer_total_amount` decimal(12,2) DEFAULT NULL,
  `shipping_carrier` varchar(100) DEFAULT NULL,
  `tracking_number` varchar(100) DEFAULT NULL,
  `shipping_fee` decimal(12,2) DEFAULT NULL,
  `shipping_fee_discount` decimal(12,2) DEFAULT NULL,
  `actual_shipping_fee` decimal(12,2) DEFAULT NULL,
  `estimated_shipping_fee` decimal(12,2) DEFAULT NULL,
  `order_chargeable_weight_gram` int(11) DEFAULT NULL,
  `commission_fee` decimal(12,2) DEFAULT NULL,
  `service_fee` decimal(12,2) DEFAULT NULL,
  `transaction_fee` decimal(12,2) DEFAULT NULL,
  `escrow_amount` decimal(12,2) DEFAULT NULL,
  `create_time` int(11) DEFAULT NULL,
  `order_created_at` datetime DEFAULT NULL,
  `update_time` int(11) DEFAULT NULL,
  `synced_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_order_shop` (`order_sn`,`shop_id`),
  KEY `idx_shop_status` (`shop_id`,`order_status`),
  KEY `idx_order_created` (`order_created_at`),
  KEY `idx_final_status` (`is_final_status`),
  KEY `idx_region_date` (`region`,`order_created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=2250 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

